class Solution:
    def minOperations(self, nums, target):
        # Independent breadth-first search over actual multiset states (only
        # feasible for small inputs), splitting elements explicitly rather
        # than using the carry/bit-sweep model.
        from collections import deque

        total = sum(nums)
        if total < target:
            return -1

        def has_subseq_sum(state, target):
            sums = {0}
            for v in state:
                sums |= {s + v for s in sums}
            return target in sums

        start = tuple(sorted(nums))
        if has_subseq_sum(start, target):
            return 0
        seen = {start}
        q = deque([(start, 0)])
        cap = 12
        while q:
            state, d = q.popleft()
            if d >= cap:
                continue
            for i, v in enumerate(state):
                if v > 1:
                    rest = list(state[:i] + state[i + 1:])
                    rest.append(v // 2)
                    rest.append(v // 2)
                    nstate = tuple(sorted(rest))
                    if nstate in seen:
                        continue
                    nd = d + 1
                    if has_subseq_sum(nstate, target):
                        return nd
                    seen.add(nstate)
                    q.append((nstate, nd))
        return -1

