var minOperations = function(nums, target) {
    let total = 0;
    for (const v of nums) total += v;
    if (total < target) return -1;
    const MAXLVL = 45;
    const have = new Array(MAXLVL + 2).fill(0);
    for (const v of nums) {
        const b = Math.round(Math.log2(v));
        have[b]++;
    }
    let ops = 0, carry = 0;
    for (let i = 0; i <= MAXLVL; i++) {
        const bit = Math.floor(target / Math.pow(2, i)) % 2;
        let avail = have[i] + carry;
        if (avail < bit) {
            let j = i + 1;
            while (j <= MAXLVL + 1 && have[j] === 0) j++;
            while (j > i) {
                have[j]--;
                have[j - 1] += 2;
                ops++;
                j--;
            }
            avail = have[i] + carry;
        }
        carry = Math.floor((avail - bit) / 2);
    }
    return ops;
};
